	@Inject
	public SecurityDslGrammarAccess(GrammarProvider grammarProvider,
			TerminalsGrammarAccess gaTerminals) {
		this.grammar = internalFindGrammar(grammarProvider);
		this.gaTerminals = gaTerminals;
		this.pApplication = new ApplicationElements();
		this.pModel = new ModelElements();
		this.pController = new ControllerElements();
		this.pSecurity = new SecurityElements();
		this.pEString = new EStringElements();
		this.pDatabase = new DatabaseElements();
		this.eEType = new ETypeElements();
		this.pAttribute = new AttributeElements();
		this.pUser = new UserElements();
		this.pOtherModel = new OtherModelElements();
		this.pRole = new RoleElements();
		this.pEndpoint = new EndpointElements();
		this.pAuthentication = new AuthenticationElements();
		this.pOtherController = new OtherControllerElements();
		this.eEEndpointMethod = new EEndpointMethodElements();
		this.eESecurityMechanism = new ESecurityMechanismElements();
		this.pJwtSecurity = new JwtSecurityElements();
		this.pEInt = new EIntElements();
		this.pClaims = new ClaimsElements();
		this.pPublicClaims = new PublicClaimsElements();
		this.pPrivateClaims = new PrivateClaimsElements();
		this.pEBoolean = new EBooleanElements();
		this.eEDatabaseType = new EDatabaseTypeElements();
		this.tNL = (TerminalRule) GrammarUtil.findRuleForName(getGrammar(), "org.ftn.domi.securitydsl.SecurityDsl.NL");
		this.tTAB = (TerminalRule) GrammarUtil.findRuleForName(getGrammar(), "org.ftn.domi.securitydsl.SecurityDsl.TAB");
	}
	
	protected Grammar internalFindGrammar(GrammarProvider grammarProvider) {
		Grammar grammar = grammarProvider.getGrammar(this);
		while (grammar != null) {
			if ("org.ftn.domi.securitydsl.SecurityDsl".equals(grammar.getName())) {
				return grammar;
			}
			List<Grammar> grammars = grammar.getUsedGrammars();
			if (!grammars.isEmpty()) {
				grammar = grammars.iterator().next();
			} else {
				return null;
			}
		}
		return grammar;
	}
	
	@Override
	public Grammar getGrammar() {
		return grammar;
	}
	
	
	public TerminalsGrammarAccess getTerminalsGrammarAccess() {
		return gaTerminals;
	}

	
